import Mathlib
 import Mathlib.Tactic.Classic
import Mathlib.Tactic.Int.Basic
import Mathlib.Tactic.Function.Basic
import Mathlib.Tactic.Array.Basic

open Function
open Array
open Lean
open Lean.Elab.Tactics
open Lean.Parser.Tactics

-- Define the SelectionSort function
def SelectionSort (a : Array Int) (n : Nat) : Array Int :=
{ induction n with | zero => a
  | succ i => let (i' := i + 1) in
    let (min := i) in
    let (j := for i in ∃nat.range (i + 1) n do i) in
    if a j < a min then min := j
    a.update min (a min) (a i) }

-- Define the main function
def main : IO Unit := do
  let array_size ← randomNat
  let a ← arrayOfNat array_size
  SelectionSort a array_size
  pure 0

-- Define the properties
def validFree (a : Array Int) : Prop := ∀i, a i = 0 ∨ ∃j, i < j ∧ a i = a j
def validDeref (a : Array Int) : Prop := ∀i, a i = some (Int.ofNat i)
def validMemtrack (a : Array Int) : Prop := ∀i, ∃j, i = j

-- Prove the properties using Lean
theorem SelectionSort_preserves_validFree : ∀{a : Array Int} (n : Nat), validFree a → validFree (SelectionSort a n) :=
begin
  intros a n h
  induction n with | zero => intros i hi; assumption
  | succ i => have min_exists : ∃j, i < j ∧ a i = a j, by {
      have i_lt_j : i < array_size, by simp [h]
      have min_def : ∃j, i < j ∧ a i = a j, by {
        rcases h with ⟨hj, hj'⟩
        exact ⟨hj, and.intro hj' (mem_range.mpr hj i_lt_j) hj'⟩
      }
      exact min_def
    },
    have min_is_i_or_smaller : i = min_exists.prop.1 ∨ min_exists.prop.1.2 < i, by {
      cases min_exists with j hj
      exact or.inl _ <| if hj then hj else hj.symm
    },
    have i_lt_min : i < min_exists.prop.1.2, by {
      have i_lt_j : i < j, by simp [min_exists.prop.1.1]
      exact i_lt_j
    },
    have a_i_eq_a_min : a i = a min_exists.prop.1.2, by simp [min_exists.prop.1.2]
    have a_min_eq_temp : a min_exists.prop.1.2 = temp, by {
      have temp_eq_a_i : temp = a i, by simp [SelectionSort.mdef]
      exact a_min_eq_temp.symm ▸ temp_eq_a_i
    },
    have a_min_is_new_min : min_exists.prop.1.2 = min, by simp [SelectionSort.mdef]
    have a_new_min_is_valid : validFree (SelectionSort a n), by {
      induction n with | zero => intros i hi; assumption
      | succ i => have i_lt_n : i < n, by simp [h]
      have new_min_is_i_or_smaller : i = min_exists.prop.1 ∨ min_exists.prop.1.2 < i, by {
        cases min_exists with j hj
