import Mathlib
 ```lean
import Mathlib.Tactic.Classic
import Mathlib.Tactic.Int.Basic
import Mathlib.Tactic.Enum.Basic
import Mathlib.Tactic.Induct
import Mathlib.Tactic.LTL

open Enum
open Function
open LTL
open Nat

-- Define bool type and if-then-else construct
inductive bool : Type where
| false : bool
| true : bool

def if_then_else (h : Bool) (p : Nat → Prop) (q : Nat → Prop) : Nat → Prop :=
if h then p else q

-- Define non-deterministic integer function
def nondet_int : Const := ∀ (), Int

-- Define main function
def main : Unit → Nat → Nat → Option Nat :=
λ _ x y,
  if x = y ∧ x > 0 then
    some (λ c, c + 1) ∘
    (while_until (λ z, z > 0) (λ z, z - 1) x) ∘
    (while_until (λ z, z > 0) (λ z, z - 1) y)
  else none

-- Define overflow property
def overflow (c : Nat) : Prop :=
c > max_int

-- Initialize main function
def init (main : Unit → Nat → Nat → Option Nat) : Unit :=
main (fun _ _ => sorry) -- Replace with the actual main function definition

-- Property to be proven: G ! overflow
def property : Prop := ∀ (c : Nat), ¬ overflow c

-- Main theorem
theorem main_theorem : CHECK (init main), LTL.G ¬ overflow :=
begin
  have_fun init_main := init main,
  have_fun main_fn := λ _ x y, main_ (fun _ _ => sorry) x y, -- Replace with the actual main function definition

  have init_main_is_total : Total (Unit → Nat → Nat → Option Nat) :=
    total_function (fun _ _ => some (fun _ _ => sorry)) init_main, -- Replace with the actual main function definition

  have main_fn_is_total : Total (Unit → Nat → Nat → Option Nat) :=
    total_function main_fn,

  have init_main_is_init : Init (Unit → Nat → Nat → Option Nat) :=
    init_main_is_total ∧
    (λ _ x y, match init_main _ x y with
      | some c => property c
      | none => true),

  have main_fn_is_loop_invariant : ∀ (c : Nat), ∀ (x y : Nat),
